        result = solve(); // Call the student's core logic
    } catch (const std::exception& e) {
        ss_output << "Exception caught: " << e.what() << std::endl;
    } catch (...) {
        ss_output << "Unknown exception caught." << std::endl;
    }

    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return {result, ss_output.str()};
}

